-- =============================================================
-- Expenses (historical import: Jan-Dec 2025)
-- =============================================================


-- =============================================================
-- MGD Returns (historical import)
-- =============================================================
-- Insert returns FIRST, then disable the collection trigger,
-- insert collections, recalculate totals, then re-enable trigger.

-- Disable the auto-sync trigger during bulk import
ALTER TABLE public.mgd_collections DISABLE TRIGGER trg_mgd_collection_sync;


-- =============================================================
-- MGD Collections (historical import)
-- =============================================================


-- Recalculate return totals from actual collection data
UPDATE public.mgd_returns r SET
  total_net_take = COALESCE(sub.sum_net, 0),
  total_mgd = COALESCE(sub.sum_mgd, 0),
  total_vat_on_supplier = COALESCE(sub.sum_vat, 0)
FROM (
  SELECT
    ret.id,
    SUM(c.net_take) AS sum_net,
    SUM(c.mgd_amount) AS sum_mgd,
    SUM(c.vat_on_supplier) AS sum_vat
  FROM public.mgd_returns ret
  LEFT JOIN public.mgd_collections c
    ON c.collection_date >= ret.period_start
    AND c.collection_date <= ret.period_end
  GROUP BY ret.id
) sub
WHERE r.id = sub.id;

-- Re-enable the auto-sync trigger
ALTER TABLE public.mgd_collections ENABLE TRIGGER trg_mgd_collection_sync;
